from typing import List

def solve(nums: List[int]) -> int:
    n = len(nums)
    max_sum = float('-inf')

    # Precompute the longest increasing and decreasing sequences
    # from each position
    inc = [0] * n
    dec = [0] * n

    # Compute increasing sequences from left
    for i in range(n):
        if i == 0:
            inc[i] = 1
        else:
            if nums[i] > nums[i-1]:
                inc[i] = inc[i-1] + 1
            else:
                inc[i] = 1

    # Compute decreasing sequences from right
    for i in range(n-1, -1, -1):
        if i == n-1:
            dec[i] = 1
        else:
            if nums[i] > nums[i+1]:
                dec[i] = dec[i+1] + 1
            else:
                dec[i] = 1

    # Try all possible middle points for the peak
    for p in range(1, n-1):
        # Find the left increasing part
        l = p
        while l > 0 and nums[l] > nums[l-1]:
            l -= 1
        # Find the right increasing part
        r = p
        while r < n-1 and nums[r] < nums[r+1]:
            r += 1

        # Check if there is a valid decreasing part between l and r
        if l < p < r:
            # Calculate the sum of the subarray from l to r
            current_sum = sum(nums[l:r+1])
            max_sum = max(max_sum, current_sum)

    return max_sum
